"""LeRobot dataset format classes for DeepLake managed ingestion.

Implements the normalized 3-table design:
  - LeRobotTasks:    task_index + task description (from tasks.jsonl)
  - LeRobotEpisodes: episode metadata + 3 camera videos (from episodes.jsonl + mp4s)
  - LeRobotFrames:   per-frame state/action scalars (from parquet files)
"""

import json
import logging
import subprocess
import sys
from pathlib import Path
from typing import Dict, Iterator, List, Optional

from .base import Format

logger = logging.getLogger(__name__)


class LeRobotTasks(Format):
    """Format for LeRobot tasks.jsonl → one row per task."""

    def __init__(self, dataset_dir: str):
        self.dataset_dir = Path(dataset_dir)
        self._tasks_file = self.dataset_dir / "meta" / "tasks.jsonl"

    def schema(self):
        return {}

    def normalize(self) -> Iterator[Dict[str, list]]:
        task_indices = []
        tasks = []

        with open(self._tasks_file) as f:
            for line in f:
                rec = json.loads(line)
                task_indices.append(rec["task_index"])
                tasks.append(rec["task"])

                if len(task_indices) >= 1000:
                    yield {
                        "task_index": task_indices,
                        "task": tasks,
                    }
                    task_indices, tasks = [], []

        if task_indices:
            yield {
                "task_index": task_indices,
                "task": tasks,
            }


class LeRobotFrames(Format):
    """Format for LeRobot parquet files → one row per frame with unpacked scalars.

    Reads parquet files for the specified chunk range and unpacks
    observation.state[8] and action[7] into individual float columns.
    """

    STATE_NAMES = ["state_x", "state_y", "state_z",
                   "state_roll", "state_pitch", "state_yaw",
                   "state_pad", "state_gripper"]
    ACTION_NAMES = ["action_x", "action_y", "action_z",
                    "action_roll", "action_pitch", "action_yaw",
                    "action_gripper"]
    _COLUMNS = (
        ["index", "episode_index", "frame_index", "task_index", "timestamp"]
        + STATE_NAMES + ACTION_NAMES
    )

    def __init__(self, dataset_dir: str, chunk_start: int = 0, chunk_end: int = 10):
        self.dataset_dir = Path(dataset_dir)
        self.chunk_start = chunk_start
        self.chunk_end = chunk_end  # inclusive

    def schema(self):
        return {}

    def normalize(self) -> Iterator[Dict[str, list]]:
        import numpy as np

        try:
            import pandas as pd
        except ImportError:
            raise ImportError("pandas required: pip install deeplake[lerobot]")

        batch = {
            "index": [], "episode_index": [], "frame_index": [],
            "task_index": [], "timestamp": [],
        }
        for name in self.STATE_NAMES + self.ACTION_NAMES:
            batch[name] = []

        batch_size = 0

        for chunk_idx in range(self.chunk_start, self.chunk_end + 1):
            chunk_dir = self.dataset_dir / "data" / f"chunk-{chunk_idx:03d}"
            if not chunk_dir.exists():
                logger.warning("Chunk dir %s not found, skipping", chunk_dir)
                continue

            parquet_files = sorted(chunk_dir.glob("episode_*.parquet"))
            logger.info("Processing chunk-%03d: %d parquet files", chunk_idx, len(parquet_files))

            for pq_path in parquet_files:
                try:
                    df = pd.read_parquet(pq_path)
                except Exception as e:
                    logger.warning("Failed to read %s: %s", pq_path, e)
                    continue

                n = len(df)
                batch["index"].extend(df["index"].tolist())
                batch["episode_index"].extend(df["episode_index"].tolist())
                batch["frame_index"].extend(df["frame_index"].tolist())
                batch["task_index"].extend(df["task_index"].tolist())
                batch["timestamp"].extend(df["timestamp"].tolist())

                # Unpack observation.state[8]
                states = np.stack(df["observation.state"].values)
                for i, name in enumerate(self.STATE_NAMES):
                    batch[name].extend(states[:, i].tolist())

                # Unpack action[7]
                actions = np.stack(df["action"].values)
                for i, name in enumerate(self.ACTION_NAMES):
                    batch[name].extend(actions[:, i].tolist())

                batch_size += n

                if batch_size >= 5000:
                    yield batch
                    # Reset using original column names only to avoid
                    # yielding empty columns on the next iteration.
                    batch = {k: [] for k in self._COLUMNS}
                    batch_size = 0

        if batch_size > 0:
            yield batch


class LeRobotEpisodes(Format):
    """Format for LeRobot episodes → one row per episode with video data.

    Pulls video files lazily per-chunk via git-lfs to manage disk space.
    After processing each chunk's videos, restores LFS pointers.
    """

    VIDEO_KEYS = [
        "observation.images.exterior_image_1_left",
        "observation.images.exterior_image_2_left",
        "observation.images.wrist_image_left",
    ]
    COL_NAMES = ["exterior_1_video", "exterior_2_video", "wrist_video"]
    _EPISODE_COLUMNS = ["episode_index", "task", "length"] + COL_NAMES

    def __init__(self, dataset_dir: str, chunk_start: int = 0, chunk_end: int = 10):
        self.dataset_dir = Path(dataset_dir)
        self.chunk_start = chunk_start
        self.chunk_end = chunk_end  # inclusive

        # Load tasks for denormalization
        tasks_file = self.dataset_dir / "meta" / "tasks.jsonl"
        self._tasks = {}
        with open(tasks_file) as f:
            for line in f:
                rec = json.loads(line)
                self._tasks[rec["task_index"]] = rec["task"]

        # Load episodes metadata
        episodes_file = self.dataset_dir / "meta" / "episodes.jsonl"
        self._episodes = {}
        with open(episodes_file) as f:
            for line in f:
                rec = json.loads(line)
                self._episodes[rec["episode_index"]] = rec

    def schema(self):
        return {
            "exterior_1_video": "BINARY",
            "exterior_2_video": "BINARY",
            "wrist_video": "BINARY",
        }

    def pg_schema(self):
        return {
            "exterior_1_video": "VIDEO",
            "exterior_2_video": "VIDEO",
            "wrist_video": "VIDEO",
        }

    def _pull_chunk_videos(self, chunk_idx: int):
        """Pull video files for one chunk via git-lfs."""
        chunk = f"chunk-{chunk_idx:03d}"
        logger.info("Pulling LFS videos for %s ...", chunk)
        result = subprocess.run(
            ["git", "lfs", "pull", f"--include=videos/{chunk}/**"],
            cwd=str(self.dataset_dir),
            capture_output=True, text=True, timeout=600,
        )
        if result.returncode != 0:
            logger.warning("git lfs pull for %s returned %d: %s",
                           chunk, result.returncode, result.stderr[:500])
        else:
            logger.info("LFS pull complete for %s", chunk)

    def _restore_chunk_pointers(self, chunk_idx: int):
        """Restore LFS pointers for a chunk to free disk space."""
        chunk = f"chunk-{chunk_idx:03d}"
        videos_dir = self.dataset_dir / "videos" / chunk
        if not videos_dir.exists():
            return

        # Delete pulled video files
        count = 0
        for cam_dir in videos_dir.iterdir():
            if cam_dir.is_dir():
                for mp4 in cam_dir.glob("*.mp4"):
                    # Only delete if it's real data (not an LFS pointer)
                    if mp4.stat().st_size > 200:
                        mp4.unlink()
                        count += 1
        if count > 0:
            # Restore LFS pointers via git checkout
            subprocess.run(
                ["git", "checkout", "--", f"videos/{chunk}/"],
                cwd=str(self.dataset_dir),
                capture_output=True, timeout=60,
            )
            logger.info("Restored %d LFS pointers for %s", count, chunk)

    def normalize(self) -> Iterator[Dict[str, list]]:
        for chunk_idx in range(self.chunk_start, self.chunk_end + 1):
            chunk = f"chunk-{chunk_idx:03d}"

            # Pull this chunk's videos
            self._pull_chunk_videos(chunk_idx)

            # Determine episode range for this chunk
            chunk_dir = self.dataset_dir / "videos" / chunk
            if not chunk_dir.exists():
                logger.warning("Video chunk dir %s not found, skipping", chunk_dir)
                continue

            # Find episodes in this chunk from the first camera dir
            first_cam = chunk_dir / self.VIDEO_KEYS[0]
            if not first_cam.exists():
                logger.warning("Camera dir %s not found, skipping", first_cam)
                continue

            episode_files = sorted(first_cam.glob("episode_*.mp4"))

            batch = {
                "episode_index": [],
                "task": [],
                "length": [],
                "exterior_1_video": [],
                "exterior_2_video": [],
                "wrist_video": [],
            }

            for ep_file in episode_files:
                # Parse episode index from filename
                ep_name = ep_file.stem  # episode_000000
                ep_idx = int(ep_name.split("_")[1])

                ep_meta = self._episodes.get(ep_idx)
                if ep_meta is None:
                    logger.warning("No metadata for episode %d, skipping", ep_idx)
                    continue

                # Read task text
                task_indices = ep_meta.get("tasks", [""])
                # Join multiple tasks if present; use first task_index to look up
                task_text = ""
                if task_indices:
                    # tasks field in episodes.jsonl is a list of task strings
                    task_text = "; ".join(t for t in task_indices if t)

                # Read all 3 camera videos
                videos = []
                skip = False
                for vkey in self.VIDEO_KEYS:
                    vpath = chunk_dir / vkey / f"{ep_name}.mp4"
                    if not vpath.exists() or vpath.stat().st_size < 200:
                        logger.warning("Video %s missing or is LFS pointer, skipping episode %d",
                                       vpath, ep_idx)
                        skip = True
                        break
                    videos.append(vpath.read_bytes())

                if skip:
                    continue

                batch["episode_index"].append(ep_idx)
                batch["task"].append(task_text)
                batch["length"].append(ep_meta.get("length", 0))
                batch["exterior_1_video"].append(videos[0])
                batch["exterior_2_video"].append(videos[1])
                batch["wrist_video"].append(videos[2])

                if len(batch["episode_index"]) >= 50:
                    yield batch
                    batch = {k: [] for k in self._EPISODE_COLUMNS}

            # Yield remaining
            if batch["episode_index"]:
                yield batch

            # Free disk: restore LFS pointers
            self._restore_chunk_pointers(chunk_idx)
